/** Information about pagination in a connection. */
export type PageInfo = {
  __typename?: 'PageInfo';
  /** When paginating forwards, the cursor to continue. */
  endCursor?: Maybe<Scalars['String']['output']>;
  /** When paginating forwards, are there more items? */
  hasNextPage: Scalars['Boolean']['output'];
  /** When paginating backwards, are there more items? */
  hasPreviousPage: Scalars['Boolean']['output'];
  /** When paginating backwards, the cursor to continue. */
  startCursor?: Maybe<Scalars['String']['output']>;
};

export type PointInput = {
  coordinates: PositionInput;
};

export type PositionInput = {
  latitude: Scalars['Float']['input'];
  longitude: Scalars['Float']['input'];
};

/** Aggregation query result of items */
export type QueryAggregationResult = {
  __typename?: 'QueryAggregationResult';
  /** The average value of the given attribute paths. */
  avgStatistics?: Maybe<Array<Maybe<Statistics>>>;
  /** The count of entities in the group. */
  count: Scalars['Int']['output'];
  /** The count of value of the given attribute paths that are not null. */
  countStatistics?: Maybe<Array<Maybe<Statistics>>>;
  /** The grouping input for the aggregation operation. */
  groupBy?: Maybe<Array<FieldAggregation>>;
  /** The maximum value of the given attribute paths. */
  maxStatistics?: Maybe<Array<Maybe<Statistics>>>;
  /** The minimum value of the given attribute paths. */
  minStatistics?: Maybe<Array<Maybe<Statistics>>>;
  /** The sum value of the given attribute paths. */
  sumStatistics?: Maybe<Array<Maybe<Statistics>>>;
};

/** A connection from an object to a list of objects of type `QueryAggregationResult`. */
export type QueryAggregationResultConnection = {
  __typename?: 'QueryAggregationResultConnection';
  /** A list of all of the edges returned in the connection. */
  edges?: Maybe<Array<Maybe<QueryAggregationResultEdge>>>;
  /** A list of all of the objects returned in the connection. This is a convenience field provided for quickly exploring the API; rather than querying for "{ edges { node } }" when no edge data is needed, this field can be used instead. Note that when clients like Relay need to fetch the "cursor" field on the edge to enable efficient pagination, this shortcut cannot be used, and the full "{ edges { node } } " version should be used instead. */
  items?: Maybe<Array<QueryAggregationResult>>;
  /** Information to aid in pagination. */
  pageInfo: PageInfo;
  /** A count of the total number of objects in this connection, ignoring pagination. This allows a client to fetch the first five objects by passing "5" as the argument to `first`, then fetch the total count so it could display "5 of 83", for example. In cases where we employ infinite scrolling or don't have an exact count of entries, this field will return `null`. */
  totalCount?: Maybe<Scalars['Int']['output']>;
};

/** An edge in a connection from an object to another object of type `QueryAggregationResult`. */
export type QueryAggregationResultEdge = {
  __typename?: 'QueryAggregationResultEdge';
  /** A cursor for use in pagination */
  cursor: Scalars['String']['output'];
  /** The item at the end of the edge */
  node: QueryAggregationResult;
};

/** Defines the kind of query to be executed */
export type QueryMode =
  | 'DEFAULT'
  | 'DOWNSAMPLING'
  | 'INTERPOLATION';

export type ResultAggregationInput = {
  avgAttributePaths?: InputMaybe<Array<InputMaybe<Scalars['String']['input']>>>;
  countAttributePaths?: InputMaybe<Array<InputMaybe<Scalars['String']['input']>>>;
  groupBy?: InputMaybe<FieldGroupByAggregationInput>;
  maxValueAttributePaths?: InputMaybe<Array<InputMaybe<Scalars['String']['input']>>>;
  minValueAttributePaths?: InputMaybe<Array<InputMaybe<Scalars['String']['input']>>>;
  sumAttributePaths?: InputMaybe<Array<InputMaybe<Scalars['String']['input']>>>;
};

/** One aggregation: source-path on the source archive plus the aggregation function and optional explicit column name. */
export type RollupAggregationInput = {
  /** Aggregation function (AVG materialises as two columns: {base}_sum and {base}_count). */
  function: CkRollupFunction;
  /** Attribute path on the source archive (must resolve against its captured Columns at activation time). */
  sourcePath: Scalars['String']['input'];
  /** Optional explicit storage column name. Null falls back to '{sourcePath}_{function}' lower-cased. */
  targetColumnName?: InputMaybe<Scalars['String']['input']>;
};

/** Rollup archive attached to a source CkArchive, with its schedule and current watermark. */
export type RollupArchiveInfo = {
  __typename?: 'RollupArchiveInfo';
  /** Number of aggregation specs configured on this rollup. */
  aggregationCount: Scalars['Int']['output'];
  /** Bucket width in milliseconds. */
  bucketSizeMs: Scalars['Long']['output'];
  /** Upper bound of the frozen range, if set. Buckets ending at or before this point are not re-aggregated by the orchestrator. */
  frozenUntil?: Maybe<Scalars['DateTime']['output']>;
  /** Exclusive end timestamp of the most recently committed bucket. Null before the first orchestrator tick. */
  lastAggregatedBucketEnd?: Maybe<Scalars['DateTime']['output']>;
  /** Runtime id of the rollup archive. */
  rtId: Scalars['OctoObjectId']['output'];
  /** Optional well-known name of the rollup archive. */
  rtWellKnownName?: Maybe<Scalars['String']['output']>;
  /** Runtime id of the source archive this rollup aggregates from. */
  sourceArchiveRtId: Scalars['OctoObjectId']['output'];
  /** Current lifecycle status: Created / Activated / Disabled / Failed. */
  status: Scalars['String']['output'];
  /** Watermark lag in milliseconds — how far behind real-time the orchestrator stays before closing a bucket. */
  watermarkLagMs: Scalars['Long']['output'];
};

/** Per-rollup metadata the studio's stream-data query editor needs (bucket size, logical attribute paths derived via chain walking). */
export type RollupQueryMetadata = {
  __typename?: 'RollupQueryMetadata';
  /** Native bucket size of this rollup in milliseconds. Drives the downsampling bucket-alignment warning. */
  bucketSizeMs: Scalars['Long']['output'];
  /** Distinct logical CK-attribute paths the rollup aggregates over. For cascade rollups these are derived via chain walking (RollupLogicalPathResolver). */
  logicalSourcePaths: Array<Scalars['String']['output']>;
  /** Runtime id of the rollup archive — echo of the request argument. */
  rtId: Scalars['OctoObjectId']['output'];
};

