/** Descriptor for a persisted stream-data query. Use the Rows sub-connection to execute the query and the Aggregations sub-connection to compute statistics over the same data. */
export type StreamDataQuery = {
  __typename?: 'StreamDataQuery';
  /** Computes statistical aggregations over the same data set as the persisted query. Accepts optional runtime field filters AND-combined with the persisted FieldFilter. */
  aggregations?: Maybe<QueryAggregationResultConnection>;
  associatedCkTypeId: Scalars['RtCkTypeId']['output'];
  columns: Array<RtQueryColumn>;
  queryRtId: Scalars['OctoObjectId']['output'];
  /** Executes the persisted stream-data query and returns the result rows. Accepts optional runtime overrides for the time range, limit, and sort order, plus additional field filters AND-combined with the persisted FieldFilter. */
  rows?: Maybe<StreamDataQueryRowDtoConnection>;
};


/** Descriptor for a persisted stream-data query. Use the Rows sub-connection to execute the query and the Aggregations sub-connection to compute statistics over the same data. */
export type StreamDataQueryAggregationsArgs = {
  after?: InputMaybe<Scalars['String']['input']>;
  aggregations: ResultAggregationInput;
  fieldFilter?: InputMaybe<Array<InputMaybe<FieldFilter>>>;
  first?: InputMaybe<Scalars['Int']['input']>;
};


/** Descriptor for a persisted stream-data query. Use the Rows sub-connection to execute the query and the Aggregations sub-connection to compute statistics over the same data. */
export type StreamDataQueryRowsArgs = {
  after?: InputMaybe<Scalars['String']['input']>;
  arg?: InputMaybe<StreamDataArguments>;
  fieldFilter?: InputMaybe<Array<InputMaybe<FieldFilter>>>;
  first?: InputMaybe<Scalars['Int']['input']>;
  sortOrder?: InputMaybe<Array<InputMaybe<Sort>>>;
};

export type StreamDataQueryColumnInput = {
  aggregationType: AggregationType;
  attributePath: Scalars['String']['input'];
};

/** A connection from an object to a list of objects of type `StreamDataQueryDto`. */
export type StreamDataQueryDtoConnection = {
  __typename?: 'StreamDataQueryDtoConnection';
  /** A list of all of the edges returned in the connection. */
  edges?: Maybe<Array<Maybe<StreamDataQueryDtoEdge>>>;
  /** A list of all of the objects returned in the connection. This is a convenience field provided for quickly exploring the API; rather than querying for "{ edges { node } }" when no edge data is needed, this field can be used instead. Note that when clients like Relay need to fetch the "cursor" field on the edge to enable efficient pagination, this shortcut cannot be used, and the full "{ edges { node } } " version should be used instead. */
  items?: Maybe<Array<StreamDataQuery>>;
  /** Information to aid in pagination. */
  pageInfo: PageInfo;
  /** A count of the total number of objects in this connection, ignoring pagination. This allows a client to fetch the first five objects by passing "5" as the argument to `first`, then fetch the total count so it could display "5 of 83", for example. In cases where we employ infinite scrolling or don't have an exact count of entries, this field will return `null`. */
  totalCount?: Maybe<Scalars['Int']['output']>;
};

/** An edge in a connection from an object to another object of type `StreamDataQueryDto`. */
export type StreamDataQueryDtoEdge = {
  __typename?: 'StreamDataQueryDtoEdge';
  /** A cursor for use in pagination */
  cursor: Scalars['String']['output'];
  /** The item at the end of the edge */
  node: StreamDataQuery;
};

/** A single row in a stream data query result. */
export type StreamDataQueryRow = {
  __typename?: 'StreamDataQueryRow';
  /** The data cells for this row, one per selected column. */
  cells?: Maybe<RtQueryCellDtoConnection>;
  ckTypeId?: Maybe<Scalars['RtCkTypeId']['output']>;
  rtChangedDateTime?: Maybe<Scalars['DateTime']['output']>;
  rtCreationDateTime?: Maybe<Scalars['DateTime']['output']>;
  rtId?: Maybe<Scalars['OctoObjectId']['output']>;
  rtWellKnownName?: Maybe<Scalars['String']['output']>;
  timestamp?: Maybe<Scalars['DateTime']['output']>;
};


/** A single row in a stream data query result. */
export type StreamDataQueryRowCellsArgs = {
  after?: InputMaybe<Scalars['String']['input']>;
  first?: InputMaybe<Scalars['Int']['input']>;
};

/** A connection from an object to a list of objects of type `StreamDataQueryRowDto`. */
export type StreamDataQueryRowDtoConnection = {
  __typename?: 'StreamDataQueryRowDtoConnection';
  /** A list of all of the edges returned in the connection. */
  edges?: Maybe<Array<Maybe<StreamDataQueryRowDtoEdge>>>;
  /** A list of all of the objects returned in the connection. This is a convenience field provided for quickly exploring the API; rather than querying for "{ edges { node } }" when no edge data is needed, this field can be used instead. Note that when clients like Relay need to fetch the "cursor" field on the edge to enable efficient pagination, this shortcut cannot be used, and the full "{ edges { node } } " version should be used instead. */
  items?: Maybe<Array<StreamDataQueryRow>>;
  /** Information to aid in pagination. */
  pageInfo: PageInfo;
  /** A count of the total number of objects in this connection, ignoring pagination. This allows a client to fetch the first five objects by passing "5" as the argument to `first`, then fetch the total count so it could display "5 of 83", for example. In cases where we employ infinite scrolling or don't have an exact count of entries, this field will return `null`. */
  totalCount?: Maybe<Scalars['Int']['output']>;
};

/** An edge in a connection from an object to another object of type `StreamDataQueryRowDto`. */
export type StreamDataQueryRowDtoEdge = {
  __typename?: 'StreamDataQueryRowDtoEdge';
  /** A cursor for use in pagination */
  cursor: Scalars['String']['output'];
  /** The item at the end of the edge */
  node: StreamDataQueryRow;
};

/** Transient stream-data queries constructed ad-hoc at execution time. */
export type StreamDataTransient = {
  __typename?: 'StreamDataTransient';
  /** Transient aggregation stream-data query. */
  aggregation?: Maybe<StreamDataTransientQueryDtoConnection>;
  /** Transient downsampling stream-data query — divides the time range into equal buckets. */
  downsampling?: Maybe<StreamDataTransientQueryDtoConnection>;
  /** Transient grouped-aggregation stream-data query. */
  groupingAggregation?: Maybe<StreamDataTransientQueryDtoConnection>;
  /** Transient simple stream-data query — projects raw attribute values. */
  simple?: Maybe<StreamDataTransientQueryDtoConnection>;
};


